curl -X POST https://api.example.com/graphql \
  -H "Authorization: Bearer {access_token}" \
  -H "Content-Type: application/json" \
  -d '{
    "query": "{ orders(status: PENDING) { id status customer { name } } }"
  }'

query GetOrders($status: OrderStatus, $page: Int, $pageSize: Int) {
  orders(status: $status, page: $page, pageSize: $pageSize) {
    data {
      id
      status
      createdAt
      customer {
        name
        phone
      }
      items {
        id
        name
        quantity
        unitPrice
      }
      totalAmount
      currency
    }
    pagination {
      page
      pageSize
      totalItems
      totalPages
      hasNext
    }
  }
}

query GetOrder($id: ID!) {
  order(id: $id) {
    id
    status
    createdAt
    updatedAt
    confirmedAt
    estimatedReadyAt
    customer { name phone }
    items {
      id name quantity
      unitPrice totalPrice notes
    }
    totalAmount currency
    payment { method status brand }
    deliveryAddress {
      street number complement
      neighborhood city state zipcode
    }
    statusHistory {
      status
      timestamp
    }
  }
}

mutation ConfirmOrder($id: ID!, $input: ConfirmOrderInput!) {
  confirmOrder(id: $id, input: $input) {
    id
    status
    estimatedReadyAt
    confirmedAt
  }
}

mutation UpdateOrderStatus($id: ID!, $input: UpdateStatusInput!) {
  updateOrderStatus(id: $id, input: $input) {
    id
    status
    previousStatus
    updatedAt
  }
}

mutation CancelOrder($id: ID!, $input: CancelOrderInput!) {
  cancelOrder(id: $id, input: $input) {
    id
    status
    cancelledAt
    cancellationReason
    refund {
      status
      amount
      estimatedDate
    }
  }
}

subscription OnOrderEvent {
  orderEvents {
    event
    eventId
    timestamp
    order {
      id
      status
      customer { name }
      totalAmount
      currency
    }
  }
}
